framework_css:
/*
======================================================================
Design System
Matches a conservative corporate WordPress-style theme for a
construction piling and earthworks company.
======================================================================
*/

:root {
    /* Brand & UI colors */
    --color-primary-blue: #0055A4;
    --color-primary-orange: #F46F1F;

    --color-secondary-dark: #333333;
    --color-secondary-mid: #555555;

    --color-accent-blue: #0055A4;

    --color-neutral-white: #FFFFFF;
    --color-neutral-bg: #F5F5F5;
    --color-neutral-border: #E0E0E0;
    --color-neutral-muted: #777777;
    --color-neutral-black: #000000;

    --color-success: #28A745;
    --color-error: #DC3545;
    --color-warning: #FFC107;
    --color-info: #17A2B8;

    /* Typography */
    --font-heading: 'Merriweather', Georgia, serif;
    --font-body: 'Source Sans 3', Helvetica, Arial, sans-serif;
    --font-code: 'Source Code Pro', Menlo, monospace;

    --font-size-h1: 32px;
    --font-size-h2: 24px;
    --font-size-h3: 18px;
    --font-size-body: 14px;
    --font-size-small: 12px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (based on 8px unit) */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 16px;
    --space-4: 24px;
    --space-5: 32px;
    --space-6: 48px;
    --space-7: 64px;

    /* Layout */
    --container-max-width: 1120px;
}

/*
======================================================================
Global Reset & Base
======================================================================
*/

*, *::before, *::after {
    box-sizing: border-box;
}

html {
    font-size: 14px; /* matches design body size */
}

body {
    margin: 0;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-secondary-dark);
    background-color: var(--color-neutral-white);
}

img {
    max-width: 100%;
    height: auto;
    border: 0;
}

ul,
ol {
    margin: 0;
    padding: 0;
}

p {
    margin: 0 0 var(--space-3);
}

h1, h2, h3, h4 {
    margin: 0 0 var(--space-3);
    font-family: var(--font-heading);
    font-weight: var(--font-weight-bold);
    color: var(--color-secondary-dark);
}

h1 {
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
}

h2 {
    font-size: var(--font-size-h2);
}

h3 {
    font-size: var(--font-size-h3);
}

a {
    color: var(--color-primary-blue);
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

code,
pre {
    font-family: var(--font-code);
}

/* Utility container for fixed-width layout */
.container {
    max-width: var(--container-max-width);
    margin-left: auto;
    margin-right: auto;
    padding-left: var(--space-3);
    padding-right: var(--space-3);
}

/* Accessible skip link (appears when focused) */
.skip-link {
    position: absolute;
    left: -9999px;
    top: auto;
    width: 1px;
    height: 1px;
    overflow: hidden;
    background: var(--color-secondary-dark);
    color: var(--color-neutral-white);
    padding: var(--space-2) var(--space-3);
    z-index: 1000;
}

.skip-link:focus {
    left: 0;
    top: 0;
    width: auto;
    height: auto;
}

/*
======================================================================
Header: Branding band
======================================================================
*/

.site-header {
    background-color: var(--color-neutral-white);
}

.top-header {
    padding-top: var(--space-5); /* 32px */
    padding-bottom: var(--space-3); /* 16px */
    border-bottom: 1px solid var(--color-neutral-border);
}

.top-header-inner {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: var(--space-4);
}

.branding {
    flex: 0 0 auto;
}

.logo-link {
    display: inline-block;
}

/* Circular logo placeholder mimicking original logo proportions */
.logo-placeholder {
    display: inline-block;
    padding: 16px 32px;
    border-radius: 999px;
    border: 3px solid var(--color-primary-blue);
    text-align: center;
}

.logo-line {
    display: block;
}

.logo-line-primary {
    font-family: var(--font-heading);
    font-size: 1.4rem;
    color: var(--color-primary-blue);
}

.logo-line-secondary {
    margin-top: 4px;
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: var(--color-primary-orange);
}

.header-contact {
    flex: 1 1 auto;
    text-align: right;
    font-size: 0.92rem;
    line-height: 1.6;
}

.header-contact-row {
    margin-bottom: 4px;
    white-space: nowrap;
}

.header-contact-row:last-child {
    margin-bottom: 0;
}

.header-contact-icon {
    margin-right: 6px;
    color: var(--color-secondary-dark);
}

.header-contact-text {
    color: var(--color-secondary-dark);
}

.header-contact-locations {
    margin-top: 4px;
    display: flex;
    flex-direction: column;
    align-items: flex-end;
}

.header-contact-label {
    font-weight: var(--font-weight-semibold);
}

.header-contact a {
    color: var(--color-secondary-dark);
}

.header-contact a:hover {
    text-decoration: underline;
}

/*
======================================================================
Main Navigation Bar
Flat, utilitarian dark bar with white text and subtle hover states.
======================================================================
*/

.main-nav {
    background-color: var(--color-secondary-dark);
    color: var(--color-neutral-white);
    border-top: 1px solid #2b2b2b;
    border-bottom: 1px solid #2b2b2b;
    font-size: 0.95rem;
}

.nav-inner {
    display: flex;
    align-items: stretch;
}

.menu {
    display: flex;
    flex-wrap: wrap;
    list-style: none;
    margin: 0;
    padding: 0;
}

.menu-item {
    position: relative;
}

.menu-item > a {
    display: flex;
    align-items: center;
    padding: 10px 20px; /* ~8-12px vertical, 16-24px horizontal */
    color: var(--color-neutral-white);
    font-weight: var(--font-weight-semibold);
    text-decoration: none;
}

.menu-item > a:hover,
.menu-item > a:focus,
.menu-item.current-menu-item > a {
    background-color: #000000;
}

.menu-icon {
    margin-right: 8px;
    font-size: 0.95rem;
}

.menu-label {
    white-space: nowrap;
}

.nav-right {
    margin-left: auto;
    display: flex;
    align-items: stretch;
}

.nav-search-icon {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0 18px;
    border-left: 1px solid rgba(255, 255, 255, 0.12);
    background-color: rgba(255, 255, 255, 0.04);
}

.nav-search-icon i {
    color: var(--color-neutral-white);
}

/*
======================================================================
Main Content Wrapper
======================================================================
*/

.site-content {
    padding-top: var(--space-5); /* 32px */
    padding-bottom: var(--space-6); /* 48px */
    background-color: var(--color-neutral-white);
}

/* This keeps the clear banded look between sections */
.site-content > .container {
    /* reserved for page-specific layouts (headings, image strips, etc.) */
}

/*
======================================================================
Footer
Simple multi-column footer on light grey, with subtle typography.
======================================================================
*/

.site-footer {
    margin-top: var(--space-5);
    background-color: var(--color-neutral-bg);
    border-top: 1px solid var(--color-neutral-border);
    font-size: 0.85rem;
}

.footer-top {
    padding-top: var(--space-5);
    padding-bottom: var(--space-4);
}

.footer-inner {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-4);
}

.footer-column {
    flex: 1 1 220px;
}

.footer-heading {
    margin: 0 0 var(--space-2);
    font-size: 1.1rem;
    font-family: var(--font-heading);
    font-weight: var(--font-weight-bold);
    color: var(--color-secondary-dark);
}

.footer-menu {
    list-style: none;
}

.footer-menu li {
    margin-bottom: 6px;
}

.footer-menu a {
    color: var(--color-neutral-muted);
    text-decoration: none;
}

.footer-menu a:hover,
.footer-menu a:focus {
    color: var(--color-primary-blue);
    text-decoration: underline;
}

.footer-bottom {
    background-color: #E0E0E0;
    border-top: 1px solid #D0D0D0;
    padding-top: 12px;
    padding-bottom: 12px;
}

.footer-bottom-inner {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-2);
}

.footer-copy {
    margin: 0;
    color: var(--color-neutral-muted);
}

.footer-credit {
    font-style: italic;
}

/*
======================================================================
Responsiveness
Maintain the conservative layout but prevent overflow on narrow screens.
======================================================================
*/

@media (max-width: 900px) {
    .top-header-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .header-contact {
        text-align: left;
    }

    .header-contact-locations {
        align-items: flex-start;
    }
}

@media (max-width: 768px) {
    .nav-inner {
        flex-wrap: wrap;
    }

    .nav-right {
        order: -1; /* search icon to the right of first row */
        margin-left: auto;
    }

    .menu-item > a {
        padding-left: 12px;
        padding-right: 12px;
    }

    .footer-inner {
        flex-direction: column;
    }
}

@media (max-width: 480px) {
    .logo-placeholder {
        padding: 12px 24px;
    }

    .header-contact-row {
        white-space: normal;
    }
}
